// Script Continued Below

var Task_uiAction = Class.create();
Task_uiAction.prototype = {
    initialize: function() {
        this.tableRouteTaskInstance = 'x_153465_discovert_route_task_instance';
		// STRY0137375, STRY0137379, STRY0137421, STRY0137422  
		this.cascadingActionLog = {"cascadeStarted": false, "role": "", "respondedBy": "", "actionTaken": "", "comment": ""};
    },

	// STRY0137375, STRY0137379, STRY0137421, STRY0137422
	_setCascadingNote: function(task, actionTaken, defaultRole) {
		var currentUser =  gs.getUserID();

		// default to assinged member as the default

		var role = this._getRole(task, defaultRole);

		var cascadingActionLog = {};
		cascadingActionLog.cascadeStarted = true;
		cascadingActionLog.role = role;
		cascadingActionLog.respondedBy = currentUser;
		cascadingActionLog.actionTaken = actionTaken;
		var comment = "";
		switch(actionTaken){
			case "reopened":
				// TODO - update message before shipping
				comment = gs.getMessage("This task has been reoponed");
				break;
			case "completed":
				comment = gs.getMessage("Tasker - This task has been automatically closed due to {0} being marked complete with the comment: {1}", [task.task_name, task.response]);
				break;
			case "cancelled":
				comment = gs.getMessage("Tasker - This task has been automatically cancelled due to {0} being cancelled with the comment: {1}", [task.task_name, task.u_cancellation_reason]);
				break;
			default:
				comment = gs.getMessage("Tasker - This task has been automatically closed due to a rejected approval on {0} with the comment: {1}", [task.task_name, task.comments_dt]);
				break;
		}
		cascadingActionLog.comment = comment;		
		return cascadingActionLog;
	},

	// DFCT0010577 
	_addResponseLog: function (task, role, respondedBy, actionTaken, response) {
		// DFCT0011187 - ACL placed on the table to prevent users from adding records.  
		// So, there is no way to add a record via UI or with GlideRecordSecure.  
		// This is the only place in the system where we write to the repspnse log.
		// It has to use Glide Record as users cannot add, edit or delete records.
		var grResponseLog = new GlideRecord('x_153465_discovert_discover_tasker_response');
        grResponseLog.initialize();
        grResponseLog.u_task_tree = task.u_task_tree;
        grResponseLog.u_task = task.getUniqueValue();
        grResponseLog.u_task_number = task.number;
        grResponseLog.u_responded_by = respondedBy;
		grResponseLog.u_role = role;

        grResponseLog.response =  response;
        grResponseLog.u_action_taken = actionTaken;
        var grOU = new GlideRecordSecure('x_153465_discovert_discover_office_hierarchy');
        if (grOU.get(task.primary_assignee)) {
            grResponseLog.u_primary_assignee = grOU.getValue('office_abbreviation');
            grResponseLog.u_primary_assignee_office_name = grOU.getValue('office_name');
        }
        grResponseLog.insert();
	},

	// DFCT0010577 - this was moved out of the business rule and performed here
	_closeRelatedTasks: function(task){
		if(task.parent){
			this._startParentOrCloseParentRecursive(task);
		}
		this._closeSubTasksRecursive(task);

		// STRY0076618 - check to see what tasks come out of wait state
		var TaskerHelper = new TaskerHelpers();
		// DFCT0011034
		TaskerHelper.onCloseCheckIfNewOrderStarts(task);
	},

	// DFCT0010577 - this was moved out of the business rule and performed here
	// DFCT0010899 - this function did more than close recursive.  It also called the update state to Start waiting parents
	//               the name was changed everywhere to reflect this
	_startParentOrCloseParentRecursive: function(task){
		// STRY0076599
		// TechDebt the text Rejected should be moved into a "constant" so all places use that constant
		var sRejected = 'Rejected';
		var TaskerHelper = new TaskerHelpers();
		if(task.parent){
			var grParent = new GlideRecord('x_153465_discovert_route_task_instance');
			if (grParent.get(task.parent)){
				// STRY0123458 removed the if on wait for subtasks
				if(grParent.work_item_type == "review_item" && task.decision == sRejected){
					// Parent task is also a task with an approve reject task type, cancel the parent
					// *************************************************************************************
					// DFCT0010460 - Tech Debt multilanguage 
					grParent.work_notes = gs.getMessage('Tasker - This Task was an Approval Task dependent on subtask completion.  A subtask was rejected causing this task to also be rejected by (Reviewer): {0} (Comment): {1}', [gs.getUserDisplayName(), task.comments]);
					grParent.decision = sRejected;
					grParent.state = 4; // closed incomplete this should be in an application constant
					grParent.active = 'false';

					// DFCT0010592
					grParent.setValue('closed_at', task.getValue('closed_at'));
					grParent.closed_by = task.closed_by;
					grParent.setValue('work_end', task.getValue('work_end'));

					//var gdt = new GlideDateTime();
					//grParent.work_end = gdt.getValue();
					grParent.update();
					// STRY0137379
					this._addResponseLog(grParent, this.cascadingActionLog.role, this.cascadingActionLog.respondedBy, this.cascadingActionLog.actionTaken, this.cascadingActionLog.comment);

					// Tech Debt - multilanguage
					gs.addInfoMessage(gs.getMessage('Tasker - {0} has been successfully {1} and marked as Completed', [grParent.number, sRejected]));
					// If we want to add parent close response log entry when a child rejection closes it, make the call right here
					// DFCT0010577 - recursively move up
					this._closeRelatedTasks(grParent);

				} else{
					// DFCT0011034
					// only close other tasks if the current task is review_item, current task was rejected, parent is not review_item and 
					if(task.work_item_type == "review_item" && task.decision == sRejected){  
						this._closeTaskOrderDependentApprovals(grParent, task, task.getValue("task_order"));						
					}

					// STRY0111263 - STRY0076597
					// a child closed, check to see if all siblings for this task are closed.
					// If all siblings are closed and parent is in wait state, checking the state for the parent will wake it up
					grParent.state = TaskerHelper.getUpdatedState(grParent);
					grParent.update();
				}
			}
		}
	},

	// STRY0111263 - Rejecting an Approval Task- Enhance cascade closing tasks to 'Descendants of Parent Approval' and 'Task Order' 
	_closeTaskOrderDependentApprovals: function(grParent, task, taskOrder){
		// TechDebt the text Rejected should be moved into a "constant" so all places use that constant
		var sRejected = 'Rejected';
		var countActiveInOrder = 0;
		var countActiveInLaterOrder = 0;
		taskOrder = parseInt(taskOrder);
		var nextOrder = taskOrder + 1;

		// close all all approval tasks in the current task order
		var grSiblings = new GlideRecord('x_153465_discovert_route_task_instance');
		var gaActiveInOrder = new GlideAggregate('x_153465_discovert_route_task_instance');
		var gaActiveInLaterOrder = new GlideAggregate('x_153465_discovert_route_task_instance');
		grSiblings.addQuery("parent", grParent.getUniqueValue());
		grSiblings.addQuery("task_order", taskOrder);
		grSiblings.addQuery("work_item_type", "review_item");
		grSiblings.addQuery("active", true);
		grSiblings.query();
		while(grSiblings.next()){
			this._closeSibling(grSiblings, task);
		}

		// count non-approval tasks (approvals were all clsed, so just count acitve), in the current order
		gaActiveInOrder.addQuery("parent", grParent.getUniqueValue());
		gaActiveInOrder.addQuery("task_order", taskOrder);
		gaActiveInOrder.addQuery("active", true);
		gaActiveInOrder.addAggregate('COUNT');
        gaActiveInOrder.query();
        if (gaActiveInOrder.next()){
			countActiveInOrder = gaActiveInOrder.getAggregate('COUNT');
		}
		// if no active task that are not review type in current order, move to next order
		if(countActiveInOrder==0){
			gaActiveInLaterOrder.addQuery("parent", grParent.getUniqueValue());
			gaActiveInLaterOrder.addQuery("task_order",">", taskOrder);
			gaActiveInLaterOrder.addQuery("active", true);
			gaActiveInLaterOrder.addAggregate('COUNT');
			gaActiveInLaterOrder.query();
			if (gaActiveInLaterOrder.next()){
				countActiveInLaterOrder = gaActiveInLaterOrder.getAggregate('COUNT');
			}
			// if there are active tasks in the next order, but not in this order, look for a non review
			// type in the next order
			if(countActiveInLaterOrder>0){
				// recurse this function to move to the next task order
				this._closeTaskOrderDependentApprovals(grParent, task, nextOrder);

			}
		}
	},
	// STRY0111263 - Rejecting an Approval Task- Enhance cascade closing tasks to 'Descendants of Parent Approval' and 'Task Order'
	_closeSibling:function(grSibling, task){
		var sRejected = 'Rejected';
		// Tech Debt - Multilanguage
		grSibling.work_notes = gs.getMessage('Tasker - This Task was an Approval Task dependent on a sibling completion.  A sibling was rejected causing this task to also be rejected by (Reviewer): {0} (Comment): {1}', [gs.getUserDisplayName(),task.comments]);
		grSibling.decision = sRejected;
		grSibling.state = 4; // closed incomplete this should be in an application constant
		grSibling.active = 'false';

		// DFCT0010592
		grSibling.setValue('closed_at', task.getValue('closed_at'));
		grSibling.closed_by = task.closed_by;
		grSibling.setValue('work_end', task.getValue('work_end'));

		//var gdt = new GlideDateTime();
		//grParent.work_end = gdt.getValue();
		grSibling.update();

		// STRY0137379
		this._addResponseLog(grSibling, this.cascadingActionLog.role, this.cascadingActionLog.respondedBy, this.cascadingActionLog.actionTaken, this.cascadingActionLog.comment);

		// Tech Debt Multilanguage
		gs.addInfoMessage(gs.getMessage("{0} has been successfully {1] and marked as Completed",[grSibling.number, sRejected]));

		// DFCT0011225 - when closing siblings, also close or delete subtasks of siblings
		this._closeSubTasksRecursive(grSibling);
	},

	// DFCT0010577 - this was moved out of the business rule and performed here
	_closeSubTasksRecursive: function(task){
		var draftState = -6;
		var sRejected = 'Rejected';
		// STRY0097131
		// This business rule didn't process these types before.  
		// To ensure Wait states of the next order and the parent are started, this business rule was turned on for theses types.
		// This if statement was added to prevent closing children when a parent sees or acknowledges one of these tasks.
		// DFCT0011050 - draft tasks need to be deleted for acknowledement and information only - this check had to move inside of the loop
		// if((task.tasker_type.getDisplayValue() != "Acknowledgement") && task.tasker_type.getDisplayValue() != "Information Only"){
		// if any subtaskers are still open close complete, close incomplete, or cancel them
		var grSubTasks = new GlideRecord('x_153465_discovert_route_task_instance');
		grSubTasks.addQuery('parent', task.getUniqueValue());
		grSubTasks.addQuery('state', '!=', 3);
		grSubTasks.addQuery('state', '!=', 4);
		grSubTasks.addQuery('state', '!=', 7);
		grSubTasks.query();

		// STRY0076598
		// set state based on how the task was closed
		var stateToSetSubtasks = null;
		if (task.u_wait_for_subtasks_to_finish == true && task.decision == sRejected){   
			// if this task was waiting for children to finish and this task was rejected and there are subtasks still open...
			// then this task was rejected b/c a subtask was rejected.  This Tasks subtasks will be closed incomplete.
			stateToSetSubtasks = 4; // closed incomplete this should be in an application constant
		} else {
			// otherwise, pass the state of this task down to its subtasks
			stateToSetSubtasks = task.state;
		}
		while (grSubTasks.next()){

			// STRY0127550 - get the value instead of the display value and compare to a constant instead of a hard coded string
			// STRY0128565 - draft tasks arenot  deleted for acknowledement and information only
			if((task.getDisplayValue("tasker_type.u_value") == TaskerTypes.CONST_TASKER_TYPE_ACKNOWLEDGEMENT) || 
				task.getDisplayValue("tasker_type.u_value") == TaskerTypes.CONST_TASKER_TYPE_INFORMATION_ONLY){
				continue;
			// STRY0122888 - if sub task is in draft state, delete instead of closing incomplete
			} else if(grSubTasks.state == draftState){
				this._deleteTasks(grSubTasks);
				continue;
			}

			// STRY0076599
			grSubTasks.state = stateToSetSubtasks;
			grSubTasks.active = 'false';

			// DFCT0010592
			grSubTasks.setValue('closed_at', task.getValue('closed_at'));
			grSubTasks.closed_by = task.closed_by;
			grSubTasks.setValue('work_end', task.getValue('work_end'));

			// Tech Debt Multilanguage
			var msg = gs.getMessage("Tasker - Parent set to:");
			// check to see if parent information is already in the close note.
			// this should only be added at the top level
			// as it flows down the chain, the top message pushes down
			if(task.close_notes.toString().indexOf(msg)==0)
				grSubTasks.close_notes = msg + ' ' + gs.getMessage("Tasker - ({0}) - Organizational Unit: ({1}) - Close Note: {2}", [task.state, task.primary_assignee, task.close_notes]);
			else
				grSubTasks.close_notes = task.close_notes;

			grSubTasks.update();
			// STRY0137379
			this._addResponseLog(grSubTasks, this.cascadingActionLog.role, this.cascadingActionLog.respondedBy, this.cascadingActionLog.actionTaken, this.cascadingActionLog.comment);

			// If we want to add subtask close response log entry when parent closes it, make the call right here
			this._closeSubTasksRecursive(grSubTasks);
		}
	},

	// DFCT0010577 - this was moved out of the business rule and performed here
	_clearOpenRequestsForTask: function(task){
		var task_state = parseInt(task.getValue('state'));

		// STRY0106180 - Find all open requests for the task and close them.
		var requests = new GlideRecord('x_153465_discovert_tasker_requests');
		requests.addQuery('u_status', 'In progress');
		requests.addQuery('parent', task.sys_id);
		requests.query();
		while(requests.next()) {
			requests.setValue("u_status", 'Completed');
			switch (task_state) {
				// Task was cancelled
				case 7:
					requests.setValue("u_response_comments", gs.getMessage('Tasker - Open Request Comment for cancelled task'));
					break;
				// Task was completed
				case 3: case 4:
					requests.setValue("u_response_comments", gs.getMessage('Tasker - Open Request Comment for Closed tasks'));
					break;
			}
			requests.update();
		}
	},

    // STRY0099532 - DIA- 'Mass Reopen' Task Tree Modal (MVP)
    uiAction_ReopenTasks: function(task, process) {
        switch (process) {
            case 'allSubtasks':
                this.reopenTaskInernal(task, true, '');
                break;
            case 'tasksByDate':
				// DFCT0010881 - changed to getValue instead of getDisplayValue
                this.reopenTaskInernal(task, true, task.getValue('closed_at'));
                break;
            default:
                this.reopenTaskInernal(task, false, '');
        }

		// check the parent to see if it has the wait flag set.  If it does then reopening the child should put it in wait state
        if (task.parent) {
            // Glide Record Secure will break this b/c of the Task Table.
            // TODO: research this and determine the right Dictionary override to allow the use of glide record secure
            var grTaskParent = new GlideRecord('x_153465_discovert_route_task_instance');
            if (grTaskParent.get(task.getValue("parent"))) {
                if (grTaskParent.u_wait_for_subtasks_to_finish == true) {
                    grTaskParent.state = -3; // -3 Waiting
                    grTaskParent.update();
                }
            }
        }		
    },


    // STRY0108861 - DIA- Cancel from Top Task Notification
    uiAction_CancelTasks: function(task, cancellationReason, cancelDateTime) {
        if (task.parent == '') {
            task.close_notes = gs.getMessage('Tasker - Top task was cancelled by: {0}. brClose Note: {1}', [gs.getUserDisplayName(), task.close_notes]);
        } else {
            task.close_notes = gs.getMessage('Tasker - Task was cancelled by: {0}. brClose Note: {1}', [gs.getUserDisplayName(), task.close_notes]);
        }
        this._cancelTasks(task, cancellationReason, cancelDateTime);
    },

    // STRY0108861 - DIA- Cancel from Top Task Notification
    _cancelTasks: function(task, cancellationReason, cancelDateTime) {
        try {
			var actionTaken = "cancelled";
			var isTopCancelledTask = false;
			// due to recursion, the top task is processed last, so set a flag to say it is top task
			if(this.cascadingActionLog.cascadeStarted!=true){
				isTopCancelledTask = true;
				this.cascadingActionLog = this._setCascadingNote(task, actionTaken, 'assigned_member');
			}
            cancellationReason = cancellationReason.replace(/<\/?[^>]+(>|$)/g, "");
            var grSubTasks = new GlideRecord(this.tableRouteTaskInstance);
			var draft = -6;
			var closeNote = gs.getMessage('Tasker - Parent task was cancelled by: {0}. brClose Note: {1}', [gs.getUserDisplayName(), task.close_notes]);
            grSubTasks.addQuery('parent', task.getUniqueValue());
			// DFCT0011240 - all tasks need to be processed becase they could have open sub Info and/or Ack tasks
            //grSubTasks.addQuery('active', true);
            // find all subtasks with this parent value
            grSubTasks.query();

            while (grSubTasks.next()) {
				// DFCT0011050 - cancel task deleting draft subotasks
				if(grSubTasks.state == draft){
					// delete subtasks and all descendants in draft state
					this._deleteTasks(grSubTasks);
				} else {
					// recursively call to cancel all descendants
					grSubTasks.close_notes = closeNote;
					this._cancelTasks(grSubTasks, cancellationReason, cancelDateTime);
				}

            }

			// DFCT0011240 - since we are processing all subtasks even closed subtasks, skip cancelling any tasks already completed
			if(task.active == true){
				task.active = false;
				// DFCT0010597
				task.setValue('closed_at', cancelDateTime.getValue());

				task.closed_by = gs.getUserID();
				task.u_cancellation_reason = cancellationReason;
				// DFCT0010597
				task.setValue('work_end', cancelDateTime.getValue());

				var strComment = task.u_cancellation_reason + '';
				var userComments = this.trimComments(strComment);

				task.work_notes = gs.getMessage('Tasker - This task has been cancelled by: {0}. brCancellation Reason: {1}', [gs.getUserDisplayName(), userComments]);

				// DFCT0010850 - clear all request fields
				task.u_clarification_requested = false;
				task.extension_requested = false;
				task.reassignment_requested = false;
				task.extended_suspense_date = null;

				task.state = 7;
				task.update();

				// STRY0137422
				if(isTopCancelledTask){
					var currentUser =  gs.getUserID();
					var role = this._getRole(task, 'assigned_member');
					this._addResponseLog(task, role, currentUser, actionTaken, task.u_cancellation_reason);
				} else {
					this._addResponseLog(task, this.cascadingActionLog.role, this.cascadingActionLog.respondedBy, this.cascadingActionLog.actionTaken, this.cascadingActionLog.comment);
				}

				// DFCT0010850
				this._clearOpenRequestsForTask(task);
			}
        } catch (ex) {
            var message = ex.message || 'Unknown error in Task_uiAction.cancelTasks()';
            var taskNumber = task.number || 'missing';

            gs.error('Error in Task_uiAction.cancelTasks(); Number: {0} \nMessage: {1}', taskNumber, message);
        }
    },

	_getRole: function(task, defaultRole){
		var currentUser =  gs.getUserID();
		var isTaskOwner = task.u_task_requester == currentUser;
		var isReviewer = task.u_reviewer == currentUser;
		var isAssignedMember = task.assigned_to == currentUser;
		var isOnBehalfOf = task.on_behalf_of == currentUser;
		var isOriginator = task.originator == currentUser;

		// default to assinged member as the default
		var role = '';


		switch(defaultRole){
			case 'reviewer':
				// change default from assinged member to reviewer
				role =  isReviewer ? 'reviewer' : isTaskOwner ? 'task_owner' : isOnBehalfOf ? 'on_behalf_of' : isOriginator ? 'originator' : isAssignedMember ? 'assigned_member' : '';
				break;
			default:
				role = isAssignedMember ? 'assigned_member' : isTaskOwner ? 'task_owner' : isOnBehalfOf ? 'on_behalf_of' : isOriginator ? 'originator' : isReviewer ? 'reviewer' : '';
				break;
		}
		return role;
	},

    // STRY0076598: New method to Reopen a Task - STRY0114416 - 5 - GlideRecordSecure - changing current
    reopenTaskInernal: function(gr_task_reopen, reopenSubtasks, taskClosedDate) {
        // this was pulled from the previous function, but needs to be updated to account for wait state
        var TaskerHelper = new TaskerHelpers();
        var msgReopenedBy = gs.getMessage('Tasker - {0} has been reopened by {1}', [gr_task_reopen.number, gs.getUserDisplayName()]);

        gr_task_reopen.active = true;

        // STRY0108861 - DIA- Cancel from Top Task Notification
        gr_task_reopen.closed_at = '';
        gr_task_reopen.closed_by = '';
        gr_task_reopen.work_end = '';

        // STRY0108861 - DIA- Cancel from Top Task Notification
        // use the previous Status, a nightly process should update
        // NOTE this was copied from reopen, this should be set based on a function, not hard coded
        //gr_task_reopen.status = "Projected on time";

        // STRY0079667
        gr_task_reopen.u_reviewer_signed = false;
        gr_task_reopen.u_completed_on_time = false;

        gr_task_reopen.work_notes = msgReopenedBy;
        gs.addInfoMessage(msgReopenedBy);

		// if we find a subtask that is reopening and the parent waits for subtasks to complete, then this task should go into wait state.
		if (gr_task_reopen.u_wait_for_subtasks_to_finish == true) {
			gr_task_reopen.state = -3; // -3 Waiting
		} else {
			gr_task_reopen.state = TaskerHelper.getUpdatedState(gr_task_reopen);
		}
		gr_task_reopen.update();

		// STRY0137204 - Define when Comment is Logged in Action Log
		var currentUser =  gs.getUserID();
		var role = this._getRole(gr_task_reopen, 'assigned_member');

		// STRY0137375
		if(this.cascadingActionLog.cascadeStarted==true){
				this._addResponseLog(gr_task_reopen, this.cascadingActionLog.role, this.cascadingActionLog.respondedBy, this.cascadingActionLog.actionTaken, this.cascadingActionLog.comment);			
		} else {
			// STRY0137637
			this._addResponseLog(gr_task_reopen, role, currentUser, 'reopened', gr_task_reopen.reopen_comments);
			this.cascadingActionLog = this._setCascadingNote(gr_task_reopen, 'reopened', 'assigned_member');
		}

        if (reopenSubtasks) {
            // Glide Record Secure will break this b/c of the Task Table.
            // TODO: research this and determine the right Dictionary override to allow the use of glide record secure
            var grSubtasksToReopen = new GlideRecord('x_153465_discovert_route_task_instance');
            grSubtasksToReopen.addQuery('parent', gr_task_reopen.getUniqueValue());
            grSubtasksToReopen.addQuery('state', 'IN', '3, 4, 7'); // 3 = Completed; 4 = Closed Incomplete; 7 = Cancelled

			// DFCT0010577 comparing to undefined wasn't working
            if (taskClosedDate !== '') {
				// DFCT0010881 - changed to use an equal query instead of greater than or eqaul.  
				//               also, changed to use value passed (was converting display value to a GlideDateTime, but not necessary)
                grSubtasksToReopen.addQuery('closed_at', taskClosedDate);
            }

            // STRY0076617 and STRY0076618 - reopen in order so that the order by waiting is applied while reopening
            grSubtasksToReopen.orderBy('task_order');
            grSubtasksToReopen.query();

			// Open the rest
            while (grSubtasksToReopen.next()) {
                // recursively reopen down the tree
                this.reopenTaskInernal(grSubtasksToReopen, true, taskClosedDate);
            }
        }
		// DFCT0010870 - check state after all subtasks are opened and reset if necessary
		var recheckTaskState = TaskerHelper.getUpdatedState(gr_task_reopen);
		if(recheckTaskState != gr_task_reopen.state){
			gr_task_reopen.state = recheckTaskState;
			gr_task_reopen.update();
		}

		return true;
    },


    // STRY0105845 
    uiAction_DeleteTasks: function(task) {
        // DFCT0011050 - find and delete all descendants
		this._deleteTasks(task);
    },

	// DFCT0011050 - go to the bottom and recursively delete all subtasks
	_deleteTasks: function(task) {
		// find and delete all descendants
        var grSubTasks = new GlideRecord('x_153465_discovert_route_task_instance');
        grSubTasks.addQuery('parent', task.getUniqueValue());
        // find all subtasks
        grSubTasks.query();
        while (grSubTasks.next()) {
            // recursively call to delete all descendants
            this._deleteTasks(grSubTasks);
        }
        task.deleteRecord();
    },


    // STRY0105845 - DFCT0010781 moved the info message out of this method and into the ui action so it isn't called for all sub tasks
	// STRY0122882 - Publish Task(s) button- New Modal to 'Choose Which Tasks to Publish'
    uiAction_PublishDraftTasks: function(task, process) {
        // Tech Debt Multilanguage
        // set the state to 0 then, call the update state method.
        task.state = -5;
        task.state = new TaskerHelpers().getUpdatedState(task);
        task.work_notes = gs.getMessage("Tasker - Task Published by") + " " + gs.getUserDisplayName();
        task.update();

		// STRY0122882 - all subtasks should publish all subtasks
		if(process == 'allSubtasks'){
			// find all children and recursively start them
			// NOTE: this needs to be GlideRecord instead of glide record secure, because users don't have the permission to change the state. 
			var grTaskChildren = new GlideRecord('x_153465_discovert_route_task_instance');
			grTaskChildren.addQuery('parent', task.getUniqueValue());
			grTaskChildren.query();
			while (grTaskChildren.next()) {
				this.uiAction_PublishDraftTasks(grTaskChildren, process);
			}
		}

    },

    // STRY0097883
    trimComments: function(strComment) {
        var maxComment = 500;
        // STRY0097883
        strComment = strComment + '';
        var userComments = strComment.replace(/<\/?[^>]+(>|$)/g, "").toString();
        userComments = userComments.length > maxComment ? userComments.substring(0, maxComment - 3) + '...' : userComments;
        return userComments;

    },

