    uiAction_AcceptExtensionRequest: function(request) {
        // Tech Debt Multilanguage
        var errorMessage = gs.getMessage("Tasker - Request  {0} did not meet the conditions to submit a Reject Extension", [request.number]);
        // TODO - multilanguage
        // we will need to make the request type field able to support multilanguage and then use a code here instead of a text value
        if (request.u_request_type == "Extension") {
            // STRY0104533
            var parentId = request.parent.toString();
            var grTask = new GlideRecord("x_153465_discovert_route_task_instance");
            if (grTask.get(parentId)) {
                var allow = new uiConditionCheck().RespondExtension(grTask);
                if (allow) {
                    // STRY0097883 - DFCT0010462
                    // Tech Debt Multilanguage
                    var taskWorkNotes = gs.getMessage("Tasker - Extension Request has been approved by {0} with the following comments: {1} and the suspense date was {2}.  The extension date requested was {3} the new suspense date approved is {4}",[gs.getUserDisplayName(), this.trimComments(request.u_response_comments), request.parent.suspense_date, request.getDisplayValue('u_requested_suspense_date'), request.getDisplayValue('requested_suspense_date_approved')]);

                    // TODO - multilanguage
                    grTask.extension_approval = 'Approved';
                    grTask.extension_requested = false;

                    //---
                    if (grTask.original_suspense_date == '') {
                        grTask.original_suspense_date = grTask.suspense_date;
                        // Tech Debt Multilanguage
                        grTask.work_notes = gs.getMessage("Tasker - The Original Suspense Date was:") + "" + grTask.original_suspense_date;
                    }
                    grTask.previous_suspense_date = grTask.suspense_date;
                    grTask.suspense_date = request.u_requested_suspense_date;
                    grTask.setValue('latest_extension_request_date', request.u_requested_suspense_date.dateNumericValue());

                    grTask.extended_suspense_date = '';

                    grTask.work_notes = taskWorkNotes;
                    grTask.update();

                    //KT: Update Request table
                    var todaysDate = new GlideDateTime();
                    // TODO - multilanguage
                    request.u_status = 'Completed'; //'Approved';
                    // TODO - multilanguage
                    request.u_response = 'Approved';
                    request.u_responded_by = gs.getUserID();
                    request.u_responded = todaysDate;
                    request.update();
					// DFCT0010918
					gs.eventQueue('x_153465_discovert.NotifyExtensionApprov', grTask);

                    //KT: Show Confirmation Message
                    gs.addInfoMessage(taskWorkNotes);
                } else gs.addErrorMessage(errorMessage);
            }
        } else gs.addErrorMessage(errorMessage);
    },

