	// DFCT0010827 - new function so completed on time, end date and empty start date are set consistently
	_setCompletedOnTime: function(task){
        var gdt = new GlideDateTime();
        // STRY0094943 - DFCT0010597
        if (!task.work_start)
            task.setValue('work_start', gdt.getValue());
		task.setValue('work_end', gdt.getValue());

        if (task.suspense_date != '') {
            if (task.suspense_date > gdt.getValue())
                task.u_completed_on_time = true;
            else
                task.u_completed_on_time = false;
        } else task.u_completed_on_time = true;
	},

    uiAction_UpdateTaskAndResponseLog: function(DecisionToClose, actionTaken, task) {
        var stateClosedFrom = task.state;
        task.decision = DecisionToClose;
        task.state = 3;
        task.active = 'false';
		// DFCT0010827 - called new function, this did not set start date when empty
		this._setCompletedOnTime(task);

        switch (actionTaken) {
			case 'abstain':
				// Tech Debt Multilanguage
				task.work_notes = gs.getMessage("Tasker - Reviewer Decision: {0} by {1}", [task.decision, task.assigned_to.getDisplayValue().toString()]);
				break;
            case 'reject':
                // STRY0097883 - DFCT0010460 
                task.work_notes = gs.getMessage("Tasker - Additional comments for the rejected Task Approval have been added by (Reviewer): {0}  (Comment): {1}",[gs.getUserDisplayName(), this.trimComments(task.comments_dt)]);
                break;
            case 'approve':
                task.work_notes = gs.getMessage('Tasker - This task has been approved by') + task.assigned_to.name;
                break;
            case 'concur':
                task.work_notes = gs.getMessage('Tasker - This task has been concurred by') + task.assigned_to.name;
                break;
            case 'nonconcur':
			case 'nonconcur_sign':
                // STRY0097883 - DFCT0010460 
                task.work_notes = gs.getMessage('Tasker - Additional comments for non-concurring of the Task have been added by (Reviewer): {0} (Comment): {1}', [gs.getUserDisplayName(), this.trimComments(task.comments_dt)]);
                break;
            case 'approve_sign':
            case 'concur_sign':
                task.work_notes = gs.getMessage('Tasker - This task has been signed by') + task.assigned_to.name;
                break;
        }

		// STRY0106180 - clear all request fields
		task.u_clarification_requested = false;
		task.extension_requested = false;
		task.reassignment_requested = false;
		task.extended_suspense_date = null;

        task.update();
		// DFCT0010577 - this was moved out of the business rule and performed here
		this._clearOpenRequestsForTask(task);
		var currentUser =  gs.getUserID();

		// DFCT0010577 
		var defaultRole='';
		if (stateClosedFrom == '14') {
			defaultRole = 'reviewer';
        } else {
			defaultRole = 'assigned_member';
        }
		var role = this._getRole(task, defaultRole);
		this._addResponseLog(task, role, currentUser, actionTaken, task.comments_dt);
		// STRY0137379 
		this.cascadingActionLog = this._setCascadingNote(task, actionTaken, defaultRole);

        gs.addInfoMessage(task.number + gs.getMessage('Tasker - has been successfully') + DecisionToClose + gs.getMessage('Tasker - and marked as Completed'));

		// DFCT0010577 - this was moved out of the business rule and performed here
		this._closeRelatedTasks(task);
    },

