    uiAction_AssignTask: function(task) {
        var now = new GlideDateTime();
        var bDateOk = true;
        if (gs.getProperty('x_153465_discovert.Suspense Dates and Expected Start Dates must be in the future') == 'true') {
            if (now > task.suspense_date && task.suspense_date != "") {
                // DFCT0010681 - fixed multilanguage while addressing other issue
                gs.addErrorMessage(gs.getMessage('The suspense date must be in the future.'));
                bDateOk = false;
            }
        }

        if (bDateOk) {
            if (task.assigned_to.nil() || task.primary_assignee.nil()) {
                var assignee = task.primary_assignee.getDisplayValue();
                task.state = -5;
                // Tech Debt Multilanguage
                task.work_notes = gs.getMessage("Tasker - Assigned to") + " " + assignee;
                task.update();
            } else {
                var assigned_to = task.assigned_to.getDisplayValue();
                task.state = 1;
                // Tech Debt Multilanguage
                task.work_notes = gs.getMessage("Tasker - Assigned to") + " " + assigned_to;
                task.update();
            }
        }
    },

