    uiAction_CreateSubtasksforEachOUMember: function(task) {
        if (!task.primary_assignee.nil()) {
            // Get the list of members in the office
            var grMem = new GlideRecordSecure('x_153465_discovert_discover_office_members');
            grMem.addQuery('discover_office_hierarchy', task.primary_assignee);
            //Only return members in the primary assignee office
            grMem.query();

            // create a subtask with the same information as the parent for each member
            while (grMem.next()) {
                this.private_functionCreateSubTaskFromParent(task, null, grMem);
            }
        }
    },

    uiAction_CreateSubtasksforEachSubOUs: function(task) {
        if (!task.primary_assignee.nil()) {
            // Get the list of OUs that are direct children of the Primary Assignee OU
            var grOUs = new GlideRecordSecure('x_153465_discovert_discover_office_hierarchy');
            grOUs.addQuery('parent', task.primary_assignee);
            //Only return members in the primary assignee office
            grOUs.query();
            // create a subtask with the same information as the parent for each member
            while (grOUs.next()) {
                this.private_functionCreateSubTaskFromParent(task, grOUs, null);
            }
        }
    },

    private_functionCreateSubTaskFromParent: function(task, primaryAssignee, assignedMember) {
        var recTaskInst = new GlideRecord('x_153465_discovert_route_task_instance');
        recTaskInst.initialize();
        recTaskInst.instructions = task.instructions;
        recTaskInst.category = task.category;
        recTaskInst.warning_hours = task.warning_hours;
        recTaskInst.classification = task.classification;
        // Set the Primary Assignee OU to the Child OU
        recTaskInst.primary_assignee = primaryAssignee ? primaryAssignee.sys_id : task.primary_assignee;
        // NOTE: May need to add members to the Additional Assignee list
        recTaskInst.assigned_to = assignedMember ? assignedMember.office_member.toString() : '';

        recTaskInst.primary_office = task.primary_office;
        recTaskInst.tasking_authority = task.tasking_authority;
        recTaskInst.short_description = task.short_description;
        recTaskInst.sub_category = task.sub_category;
        recTaskInst.parent = task.sys_id;
        recTaskInst.task_order = 1;
		// STRY0126732
		recTaskInst.tasker_type = task.tasker_type;

        // NOTE this should not be necessary, but the business rule that keeps these 2 in sync is not firing on this ui action
        recTaskInst.order = 1;
        // STRY0076880
        recTaskInst.u_wait_for_subtasks_to_finish = task.u_wait_for_subtasks_to_finish;
        // ***************** Start of changes	*****************
        // STRY0011008 - RAJ 2018-02-23 add logic to set dates while creating sub tasks
        //               the date logic used to be in a business rule, but that had negative impact on setting dates throughout a process tree
        var gdt = new GlideDateTime();
        var durationAdd;
        // Use parent to set Estimated Start, if child estimated start not set
        //  STRY0076973 - fix start date copy to subtask issue
        if (!task.expected_start.nil()) {
            recTaskInst.setValue('expected_start', task.expected_start.dateNumericValue());
            gdt.setValue(recTaskInst.expected_start.dateNumericValue());
        } else {
            recTaskInst.setValue('expected_start', gdt.getNumericValue());
        }

        //       If use the parent values for suspense date instead of calculating based on duration
        if (!task.suspense_date.nil()) {
            recTaskInst.setValue('suspense_date', task.suspense_date.dateNumericValue());
            recTaskInst.setValue('due_date', task.suspense_date.dateNumericValue());
        } else {
            // NOTE: logicall calculating the duration below should only be done if the parent task has no suspsense date
            // if current record has no duration and no supsense date, and the parent has no suspense date
            // then, set the task's date to add the the parent's duration
            if (!task.calendar_duration.nil()) {
                // STRY0110317 - updated to use schedule on when creating subtasks where there is no suspense date
                //               and a duration on the parent task
                var tdc = new TaskerDurationCalculator();
                recTaskInst.calendar_duration = task.calendar_duration;
                durationAdd = task.calendar_duration.dateNumericValue();
                gdt.setValue(tdc.calculateEndDate(recTopTempTask, (durationAdd), gdt));
                recTaskInst.setValue('suspense_date', gdt.getValue());
                recTaskInst.setValue('due_date', task.suspense_date.dateNumericValue());
            }
        }

        // ***************** End of changes	*****************
        recTaskInst.originator = gs.getUserID();
        recTaskInst.insert();
    },

    uiAction_CreateSuggestedTask: function(action, suggestedTask) {
        var taskerTable = 'x_153465_discovert_route_task_instance';
        var grTasker = new GlideRecord(taskerTable);
        var a_count = new GlideAggregate('sys_attachment');
        a_count.addQuery('table_sys_id', suggestedTask.sys_id);
        a_count.addAggregate('COUNT');
        a_count.query();
        var numAttachments = 0;
        if (a_count.next())
            numAttachments = a_count.getAggregate('COUNT');
        grTasker.initialize();
        grTasker.short_description = suggestedTask.suggested_short_description;
        grTasker.instructions = suggestedTask.suggested_tasker_instructions;
        // STRY0048709
        grTasker.u_objective = suggestedTask.suggested_tasker_instructions;
        grTasker.suggested_task = suggestedTask.sys_id;
        //HT STRY0042785 set primary assignee, primary office and tasking authority to default OU of internal email sender
        if (suggestedTask.sender_internal_user) {
            var defaultOU = '';
			// STRY0131148 - change to new table
            var grOU= new GlideRecordSecure('x_153465_discovert_organization_user');
            grOU.addQuery('u_tasker_user', suggestedTask.sender_internal_user);
            grOU.setLimit(1);
            grOU.query();
            while (grOU.next()) {
                defaultOU = grOU.getValue("u_default_ou");
            }
            if (defaultOU) {
                grTasker.primary_assignee = defaultOU;
                grTasker.primary_office = defaultOU;
                grTasker.tasking_authority = defaultOU;
            }
        }
        // Tech Debt Multilanguage
        grTasker.work_notes = gs.getMessage("Tasker - This task was created from Suggested Task #: {0} \n Sender: {1} \n Sender Email: {2} \n Subject Line: {3} \n Date Emailed: {4} \n Number of attachments: {5}",[suggestedTask.number.getDisplayValue(), suggestedTask.sender_internal_user.name, suggestedTask.senderemail, suggestedTask.email_subject, suggestedTask.sys_created_on, numAttachments]);

        // STRY0084599 - Need a way for deliver and customers to better synchronize field updates and changes
        grTasker = new CustomTaskerFieldHelper().mapFieldDataOnAction('suggestedTasktoTask', suggestedTask, grTasker);
        grTasker.insert();
        suggestedTask.u_created_task = grTasker.sys_id;
        suggestedTask.tasker_created = true;
        suggestedTask.active = false;
        suggestedTask.update();

		var oUserPref = new x_153465_discovert.tasker_User_Form_Preferences();
		var userPreferences = oUserPref.loadMyFormPreferences();
		var url_Properties = oUserPref.get_URL_Properties_for_Task_Based_on_Prefrences(grTasker.sys_id,'sp');
        // Tech Debt Multilanguage
        var infoMsg = '<a href="../' + url_Properties.portal_url_ref + 
			'?id=' + url_Properties.pageId + '&table=' + taskerTable + 
			'&sys_id=' + grTasker.sys_id + '&spa=1" target="_top" >' + 
			suggestedTask.u_created_task.getDisplayValue() + 
			' ' + gs.getMessage("Tasker - has been created based on this suggestion") +
			'</a>. ' + gs.getMessage("Tasker - Please Wait. You are being redirected to the new Task.");
        gs.addInfoMessage(infoMsg);
        // Redirect
        if (typeof spModal == 'undefined') {
            action.setRedirectURL(grTasker);
        }

    },

    uiAction_CreateTask: function(action, task) {
        // v2.5.13 | 08.08.2020 | STRY0076605:  Sequential Review
        var insertTaskerHelper = new TaskerHelpers();
        var initialState = insertTaskerHelper.getInitialState(task);
        task.state = initialState;
        // STRY0072379
        var bDateOk = true;
        var now = new GlideDateTime();
        if (gs.getProperty('x_153465_discovert.Suspense Dates and Expected Start Dates must be in the future') == 'true') {
            if (now > task.suspense_date && task.suspense_date != "") {
                // Tech Debt Multilanguage
                gs.addErrorMessage(gs.getMessage("Tasker - The suspense date must be in the future."));
                bDateOk = false;
            }
        }
		// STRY0122589 
		var isActiveUnderDraft = false;
		if(task.getValue('parent') != null){
			var grParent = new GlideRecordSecure('x_153465_discovert_route_task_instance');
			if(grParent.get(task.getValue('parent'))){
				if(grParent.state == -6){
					gs.addInfoMessage(gs.getMessage("An active task can't be created under a task in Draft State.  The Task was saved as a Draft Task"));
				}
			}
		}		
        if (bDateOk) {
            task.insert();
            // Redirect
            if (typeof spModal == 'undefined') {
                action.setRedirectURL(task);
            }
        }
    },

	uiAction_CreateDraftTask: function(action, task) {
		var bDateOk = true;
        var now = new GlideDateTime();

		task.state = -6; // Draft

		if (gs.getProperty('x_153465_discovert.Suspense Dates and Expected Start Dates must be in the future') == 'true') {
            if (now > task.suspense_date && task.suspense_date != "") {
                // Tech Debt Multilanguage
                gs.addErrorMessage(gs.getMessage("Tasker - The suspense date must be in the future."));
                bDateOk = false;
            }
        }

        if (bDateOk) {
            task.insert();
        }
    },

