    uiAction_Promote: function(task) {
        var grParentInstance = new GlideRecord('x_153465_discovert_route_task_instance');
        grParentInstance.initialize();

        // skip assignment, it will be handled by tasking authority
        //task.assigned_to = grSourceDefinition.assigned_to_individual;
        grParentInstance.instructions = task.instructions;
        grParentInstance.category = task.category;
        grParentInstance.warning_hours = task.warning_hours;
        grParentInstance.classification = task.classification;
        // TODO, FIND PARENT OU OF CURRENT TASK
        var grOU = new GlideRecordSecure('x_153465_discovert_discover_office_hierarchy');
        grOU.addQuery('sys_id', task.primary_assignee);
        grOU.query();
        if (grOU.next()) {
            grParentInstance.primary_assignee = grOU.parent;
        }

        grParentInstance.primary_office = task.primary_office;
        grParentInstance.task_order = 1;
        // TODO - don't do this with a single copy, need to determine the right way to do this
        //grParentInstance.response
        grParentInstance.short_description = task.short_description;
        grParentInstance.sub_category = task.sub_category;
        grParentInstance.calendar_duration = task.calendar_duration;
        grParentInstance.tasker_type = task.tasker_type;
        grParentInstance.tasking_authority = task.tasking_authority;
        grParentInstance.demo_data = task.demo_data;
        grParentInstance.originator = task.originator;
        grParentInstance.insert();
        task.parent = grParentInstance.sys_id;
        task.update();

        // NOTE: we may want to also copy the response documents from source to destination.  Or, the attachments object might be just fine.
        // TODO IF WE TURN THIS BACK ON, NEED TO ADD TO THE OTHER COPY MECHANISM SIMILAR TO CREATE WITH A PARENT, WE WILL NEED TO DO CREATE WITH A CHILD
        GlideSysAttachment.copy('x_153465_discovert_route_task_instance', task.sys_id, 'x_153465_discovert_route_task_instance', grParentInstance.sys_id);
    },

    uiAction_RejectAssignment: function(task) {
        if (task.comments.nil()) {
            gs.addErrorMessage(gs.getMessage('Additional comments are required when rejecting a Task'));
        } else {
            task.state = 11;
            task.assigned_to = '';
            // STRY0097883
            var workNotes = gs.getMessage('Tasker - Additional comments for the Task Rejection have been added by');
            workNotes = workNotes + gs.getMessage('Tasker -  (Assigned Member Rejecting):') + gs.getUserDisplayName();
            workNotes = workNotes + gs.getMessage('Tasker -  (Comment):') + this.trimComments(task.comments);
            task.work_notes = workNotes;

            task.update();
            gs.addInfoMessage(task.number + gs.getMessage('Tasker -  has been rejected'));
            // Redirect
            if (typeof spModal == 'undefined') {
                // action.setRedirectURL(task);
                gs.setRedirect(task);
            }

        }
    },

    uiAction_RejectExtensionRequest: function(request) {
        // Tech Debt Multilanguage
        var errorMessage = gs.getMessage("Tasker - Request {0} did not meet the conditions to submit a Reject Extension", [request.number]);

        // TODO - multilanguage
        if (request.u_request_type == "Extension") {
            // STRY0104533
            var parentId = request.parent.toString();
            var grTask = new GlideRecord("x_153465_discovert_route_task_instance");
            if (grTask.get(parentId)) {
                var allow = new uiConditionCheck().RespondExtension(grTask);
                if (allow) {
                    // STRY0097883
                    // Tech Debt Multilanguage
                    var taskWorkNotes = gs.getMessage("Tasker - Extension Request has been rejected by {0} with the following comments: {1} Note: The suspense date has not been updated.", [gs.getUserDisplayName(), this.trimComments(request.u_response_comments)]);
                    grTask.latest_extension_request_date = request.u_requested_suspense_date;
                    grTask.extended_suspense_date = '';
                    // TODO - multilanguage
                    grTask.extension_approval = 'Rejected';
                    grTask.extension_requested = false;
                    grTask.work_notes = taskWorkNotes;
                    grTask.update();

                    var todaysDate = new GlideDateTime();
                    // TODO - multilanguage
                    request.u_status = 'Completed'; //'Approved';
                    // TODO - multilanguage
                    request.u_response = 'Rejected';
                    request.u_responded_by = gs.getUserID();
                    request.u_responded = todaysDate;
                    request.update();

					// DFCT0010919
					gs.eventQueue('x_153465_discovert.NotifyExtensionReject', grTask);

                    gs.addInfoMessage(taskWorkNotes);
                } else gs.addErrorMessage(errorMessage);
            }
        } else gs.addErrorMessage(errorMessage);
    },

