    uiAction_SaveAsTemplate: function(task) {
        // start the process of creating a new process definition
        gs.eventQueue('x_153465_discovert.Save_as_Template', task, 'Save as Template', gs.getUserID());
        // Tech Debt Multilanguage
        gs.addInfoMessage("'" + task.task_name + "' " + gs.getMessage("Tasker - has been saved as a Template. You can find it under") + '<a href="?id=discovertasker_processtemplatelist&table=x_153465_discovert_discover_routing_template&filter=process_level%3Dglobal_process%5ENQprocess_level%3Dou_process%5ENQprocess_level%3Dmy_process%5Eprocess_ownerDYNAMIC90d1921e5f510100a9ad2572f2b477fe%5EEQ"> Personal Templates </a>');

        var templateName = task.short_description;
        var gr = new GlideAggregate('x_153465_discovert_discover_routing_template');
        gr.addQuery('template_name', templateName);
        gr.setLimit(1);
        gr.query();
        if (gr.next()) {
            // Tech Debt Multilanguage
            gs.addInfoMessage(gs.getMessage("Tasker - There is already a Template with that name.  Saving Template as a copy."));
        }
    },

