    uiAction_SendClarification: function(request) {
        // Tech Debt Multilanguage
        var errorMessage = gs.getMessage("Tasker - Request {0} did not meet the conditions to provide Clarification",[request.number]);

        if (request.u_request_type == "Clarification") {
            var parentId = request.parent.toString();
            var grTask = new GlideRecord("x_153465_discovert_route_task_instance");
            if (grTask.get(parentId)) {
                var allow = new uiConditionCheck().RespondClarification(grTask);
                if (allow) {
                    // STRY0097883
                    // Tech Debt Multilanguage
                    var taskWorkNotes = gs.getMessage("Tasker - Clarification Request has been provided by {0} with the following comments: {1}",[gs.getUserDisplayName(),this.trimComments(request.u_response_comments)]);
                    grTask.u_clarification_requested = false;
                    grTask.work_notes = taskWorkNotes;
                    grTask.update();

                    //KT: Update Request table
                    var todaysDate = new GlideDateTime();
                    // TODO - multilanguage
                    request.u_status = 'Completed'; //'Approved';
                    // TODO - multilanguage
                    request.u_response = 'Provided';
                    request.u_responded_by = gs.getUserID();
                    request.u_responded = todaysDate;
                    request.update();

                    //KT: Show Confirmation Message
                    if (gs.isMobile()) {
                        // Tech Debt Multilanguage
                        gs.addInfoMessage(gs.getMessage("Tasker - Response submitted."));
                    } else {
                        gs.addInfoMessage(taskWorkNotes);
                    }

                    //-------
                    //get the person who is going to receive
                    var clarificationProvider = gs.getUserDisplayName().toString();
                    var recipient = request.getValue('u_requested_by').toString();
                    // STRY0073598
                    // Assigned To, if active and assigned to is set
                    if (grTask.active && (grTask.assigned_to + '' != '')) {
                        recipient = recipient + ',' + grTask.getValue('assigned_to').toString();
                    }
                    if (grTask.active && (grTask.state == 14) && (grTask.u_reviewer + '' != '')) {
                        recipient = recipient + ',' + grTask.getValue('u_reviewer').toString();
                    }
                    if (grTask.active && (grTask.assigned_to + '' == '') && (grTask.primary_assignee + '' != '') && (grTask.primary_assignee.tasking_authorities + '' != '')) {
                        recipient = recipient + ',' + grTask.primary_assignee.tasking_authorities;
                    }
                    if (grTask.active && (grTask.assigned_to + '' == '') && (grTask.primary_assignee + '' == '')) {
                        recipient = recipient + ',' + grTask.primary_office.u_global_authorities;
                    }
                    gs.eventQueue('x_153465_discovert.NotifClarificationPro', grTask, clarificationProvider, recipient);
                    //-------
                } else gs.addErrorMessage(errorMessage);
            }
        } else gs.addErrorMessage(errorMessage);
    },

    uiAction_SendToReview: function(task) {
        // STRY0097883 - DFCT0010460-2
        task.work_notes = task.number + " " + gs.getMessage('Tasker -  has been sent to review by') + " " + 
			gs.getMessage('Tasker - (Assigned Member):') + ' ' + gs.getUserDisplayName() + " " +
			gs.getMessage('Tasker -  (Comment):') + this.trimComments(task.response);

        // STRY0094943
        var gdt = new GlideDateTime();
        if (!task.work_start)
            task.work_start = gdt.getValue();

        task.state = 14;
        task.update();

		// STRY0137204 - Define when Comment is Logged in Action Log
		var currentUser =  gs.getUserID();

		// if user is not the assigned member, check to see if taskit is the owner and change to task owner
		// if the assinged_member and task owner are the same person leave the role as assigned_member
		// if it isn't the assigned_member or the task owner, set it to the reviewer b/c that is the role the person took
		var actionTaken = "sent_to_review";
		var role = this._getRole(task, 'assigned_member');
		this._addResponseLog(task, role, currentUser, actionTaken, task.response);

        gs.addInfoMessage(task.number + gs.getMessage('Tasker -  has been sent to review'));
    },

    uiAction_SendToRework: function(task) {
        // STRY0097883 - DFCT0010460-2
        task.work_notes = task.number + " " + gs.getMessage('Tasker -  has been sent to rework by') + ' ' +
			gs.getMessage('Tasker - (Reviewer):') + gs.getUserDisplayName() + ' ' +
			gs.getMessage('Tasker -  (Comment):') + this.trimComments(task.rework_comments);
        task.state = 15;
        task.update();

		// STRY0137204 - Define when Comment is Logged in Action Log
		var currentUser =  gs.getUserID();

		// if user is not the reviewer, check to see if task owner and change to task owner
		// if the reviewer and task owner are the same person leave the role as reviewer
		// if it isn't the reviewer or the task owner, set it to the reviewer b/c that is the role the person took
		var role = this._getRole(task, 'reviewer');
		this._addResponseLog(task, role, currentUser, "sent_to_rework", task.rework_comments);
        gs.addInfoMessage(task.number + gs.getMessage('Tasker -  has been sent to rework'));
    },

